// Code: Kunden + Termine zusammenführen (v12)
// Input 0: Alle Kunden mit Confluence PageID
// Input 1: Alle aktiven Termine (Loeschen=false, Datum >= heute)
//
// Ergebnis: pro Kunde ein Item mit seinen Terminen (kann leer sein)
// → leere Terminliste = Panel wird geleert = gelöschte Termine verschwinden

var today = new Date();
today.setHours(0, 0, 0, 0);

// Input 0: Kunden
var kundenItems = $input.all().filter(function(i) { return i.pairedItem && i.pairedItem.input === 0; });
// Input 1: Termine  
var termineItems = $input.all().filter(function(i) { return i.pairedItem && i.pairedItem.input === 1; });

// Fallback: wenn pairedItem nicht verfügbar (ältere n8n-Versionen)
// beide Inputs über $('...').all() holen
var alleItems = $input.all();

// Kunden-Map aufbauen: kundePageId → { confluencePageId, termine[] }
var kundeMap = {};

// Alle Kunden-Items verarbeiten (aus erstem Notion-Node)
var kundenRaw = $('Notion: Alle Kunden holen').all();
for (var k = 0; k < kundenRaw.length; k++) {
  var kProps = kundenRaw[k].json;
  var pageId = kProps.id || '';
  var confPageId = kProps.property_confluence_page_i_d
    || kProps.property_confluence_page_id
    || kProps.property_confluence_pageid
    || '';
  if (!confPageId) continue; // Kunden ohne Confluence-Seite überspringen
  kundeMap[pageId] = {
    kundePageId:     pageId,
    confluencePageId: confPageId,
    spaceKey:        kProps.property_confluence_space_key || '',
    termine:         []
  };
}

// Alle aktiven Termine verarbeiten und Kunden zuordnen
var termineRaw = $('Notion: Aktive Termine holen').all();
for (var t = 0; t < termineRaw.length; t++) {
  var props = termineRaw[t].json;

  var datumObj = props.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start)                                 { datumRaw = datumObj.start; }
  else if (typeof datumObj === 'string' && datumObj.length >= 10) { datumRaw = datumObj; }
  if (!datumRaw) continue;
  if (new Date(datumRaw.substring(0, 10)) < today) continue;

  var datumIso   = datumRaw.substring(0, 10);
  var dp         = datumIso.split('-');
  var datumStr   = dp[2] + '.' + dp[1] + '.' + dp[0];
  var uhrzeitStr = '';
  var tIdx       = datumRaw.indexOf('T');
  if (tIdx !== -1) { uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6); }

  var titel = String(props.property_titel || props.name || 'Kein Titel');
  var ort   = String(props.property_ort   || '');

  var kundenIds = props.property_kunden || [];
  if (!Array.isArray(kundenIds)) kundenIds = [kundenIds];

  for (var j = 0; j < kundenIds.length; j++) {
    var kId = kundenIds[j];
    if (!kId || !kundeMap[kId]) continue;
    kundeMap[kId].termine.push({ datumIso, datumStr, uhrzeitStr, titel, ort });
  }
}

// Ergebnis: alle Kunden mit Confluence-Seite ausgeben
var result = [];
var keys = Object.keys(kundeMap);
for (var ki = 0; ki < keys.length; ki++) {
  var e = kundeMap[keys[ki]];
  e.termine.sort(function(a,b){ return a.datumIso<b.datumIso?-1:a.datumIso>b.datumIso?1:0; });
  result.push({ json: e });
}
return result;

// Code: Tabelle aufbauen (v12 - Full Replace)
// Liest confluencePageId direkt aus loopItem (nicht aus Notion-Kundendaten)
// da wir diese bereits im Merge-Node haben

var page     = $json;
var loopItem = $('Loop: Ein Kunde pro Durchlauf').item.json;
var termine  = loopItem.termine || [];

var esc = function(s) {
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
};

var pageId       = page.id    || '';
var pageTitle    = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value) ? page.body.storage.value : '';

// Panel finden
var panelTitles = [
  'N\u00e4chste Termine','N&auml;chste Termine',
  'N&#228;chste Termine','N&#xE4;chste Termine','N&#xe4;chste Termine'
];
var titleIdx = -1;
for (var ti = 0; ti < panelTitles.length; ti++) {
  titleIdx = html.indexOf(panelTitles[ti]);
  if (titleIdx !== -1) break;
}
if (titleIdx === -1) throw new Error('Heading "Nächste Termine" nicht gefunden. pageId:' + pageId);

var panelMacroTag = '<ac:structured-macro ac:name="panel"';
var panelStart    = html.indexOf(panelMacroTag, titleIdx);
if (panelStart === -1) throw new Error('Panel-Makro nicht gefunden. pageId:' + pageId);

var panelEndTag   = '</ac:structured-macro>';
var panelEnd      = html.indexOf(panelEndTag, panelStart);
if (panelEnd === -1) throw new Error('Panel-Ende nicht gefunden. pageId:' + pageId);
var panelEnd_full = panelEnd + panelEndTag.length;
var panelBlock    = html.substring(panelStart, panelEnd_full);

// Tabelle aufbauen
var tableLocalId = 'termine-tbl-' + pageId + '-0001';
var headerRow = '<tr>'
  + '<th ac:local-id="'+tableLocalId+'-h1"><p><strong>Datum</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h2"><p><strong>Uhrzeit</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h3"><p><strong>Titel</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h4"><p><strong>Ort</strong></p></th>'
  + '</tr>';

var dataRows = '';
for (var ri = 0; ri < termine.length; ri++) {
  var t = termine[ri];
  var rowId = tableLocalId + '-r' + ri;
  dataRows += '<tr ac:local-id="'+rowId+'">'
    + '<td ac:local-id="'+rowId+'-c1"><p>'+esc(t.datumStr)  +'</p></td>'
    + '<td ac:local-id="'+rowId+'-c2"><p>'+esc(t.uhrzeitStr)+'</p></td>'
    + '<td ac:local-id="'+rowId+'-c3"><p>'+esc(t.titel)     +'</p></td>'
    + '<td ac:local-id="'+rowId+'-c4"><p>'+esc(t.ort)       +'</p></td>'
    + '</tr>';
}

var tableHtml = termine.length > 0
  ? '<table data-table-width="760" data-layout="default" ac:local-id="'+tableLocalId+'">'
    + '<tbody>'+headerRow+dataRows+'</tbody></table>'
  : '<p></p>';

var newRTB = '<ac:rich-text-body>' + tableHtml + '</ac:rich-text-body>';

var newPanelBlock;
var selfClosing = '<ac:rich-text-body />';
if (panelBlock.indexOf(selfClosing) !== -1) {
  newPanelBlock = panelBlock.replace(selfClosing, newRTB);
} else {
  var rtbOpen  = '<ac:rich-text-body>';
  var rtbClose = '</ac:rich-text-body>';
  var rtbStart = panelBlock.indexOf(rtbOpen);
  var rtbEnd   = panelBlock.indexOf(rtbClose);
  if (rtbStart===-1||rtbEnd===-1) throw new Error('ac:rich-text-body nicht gefunden. pageId:'+pageId);
  newPanelBlock = panelBlock.substring(0,rtbStart) + newRTB
    + panelBlock.substring(rtbEnd+rtbClose.length);
}

html = html.substring(0,panelStart) + newPanelBlock + html.substring(panelEnd_full);
return { json: {
  pageId,
  pageTitle,
  newVersion:  currentVersion + 1,
  updatedHtml: html,
  confluencePageId: loopItem.confluencePageId
}};
